"use strict";function initText(){document.querySelectorAll("[data-term]").forEach(function(t){var e=terms[t.getAttribute("data-term")];t.textContent=e[Math.floor(Math.random()*e.length)]}),document.querySelectorAll("[data-date]").forEach(function(t){t.textContent=(new Date).getFullYear()-Math.floor(35*Math.random())}),document.querySelectorAll("[data-note]").forEach(function(t){t.textContent=Math.floor(75*Math.random())+"/"+Math.floor(26*Math.random()+75)})}initText(),document.getElementById("generate").addEventListener("click",function(){initText()});